package com.socialblog.follower.web;import jakarta.servlet.*;import jakarta.servlet.http.*;import org.springframework.core.Ordered;import org.springframework.core.annotation.Order;import org.springframework.stereotype.Component;import org.springframework.web.filter.OncePerRequestFilter;import java.io.IOException;import java.util.UUID;@Component @Order(Ordered.HIGHEST_PRECEDENCE)public class CorrelationIdFilter extends OncePerRequestFilter{public static final String HEADER="X-Correlation-ID",ATTRIBUTE=CorrelationIdFilter.class.getName()+".id";protected void doFilterInternal(HttpServletRequest q,HttpServletResponse s,FilterChain c)throws ServletException,IOException{String id=q.getHeader(HEADER);if(id==null||id.isBlank()||id.length()>100)id=UUID.randomUUID().toString();q.setAttribute(ATTRIBUTE,id);s.setHeader(HEADER,id);c.doFilter(q,s);}}
